//! Golden block fixtures from Polygon mainnet.
//!
//! ## Two sources of data:
//!
//! 1. **`generated.rs`** — Auto-generated by `scripts/fetch_golden_blocks.py` with real
//!    on-chain data (header hashes, state roots, receipt roots, etc.)
//!
//! 2. **`known_values()`** below — Hardcoded ground-truth values that we KNOW are correct
//!    independent of any RPC fetch. These serve as a fallback and sanity check.
//!
//! Run `python3 scripts/fetch_golden_blocks.py` to generate `generated.rs`.
//! Until then, use `known_values()` for testing.

// Include auto-generated fixtures when available.
// Uncomment after running fetch_golden_blocks.py:
// mod generated;
// pub use generated::*;


// ============================================================================
// KNOWN VALUES — hardcoded ground truth independent of RPC
// These are values we KNOW from the protocol spec, not from fetching blocks.
// They can be used immediately without running the fetch script.
// ============================================================================

