/// Known boundary conditions — blocks that are on specific boundaries.
pub fn known_boundary_blocks() -> Vec<KnownBoundaryBlock> {
    vec![
        // Sprint boundaries (block % sprint_size == 0)
        KnownBoundaryBlock { block: 38_188_992, is_sprint_start: true, sprint_size: 64, is_span_start: false, span_size: 6400 },
        KnownBoundaryBlock { block: 38_189_056, is_sprint_start: true, sprint_size: 16, is_span_start: false, span_size: 6400 },  // Delhi itself
        KnownBoundaryBlock { block: 38_189_072, is_sprint_start: true, sprint_size: 16, is_span_start: false, span_size: 6400 },
        KnownBoundaryBlock { block: 50_523_000, is_sprint_start: false, sprint_size: 16, is_span_start: false, span_size: 6400 }, // Agra: 50523000 % 16 = 8, NOT sprint start!
        KnownBoundaryBlock { block: 83_756_500, is_sprint_start: false, sprint_size: 16, is_span_start: false, span_size: 1600 }, // Lisovo: 83756500 % 16 = 4, NOT sprint start!

        // Span boundaries (block % span_size == 0)
        KnownBoundaryBlock { block: 51_200,     is_sprint_start: true,  sprint_size: 16, is_span_start: true,  span_size: 6400 },  // span 8
        KnownBoundaryBlock { block: 6_400,      is_sprint_start: true,  sprint_size: 64, is_span_start: true,  span_size: 6400 },  // span 1 (pre-Delhi)
        KnownBoundaryBlock { block: 77_416_000, is_sprint_start: true,  sprint_size: 16, is_span_start: true,  span_size: 1600 },  // first post-Rio span boundary (77416000 % 1600 == 0)

        // Block 0 special case
        KnownBoundaryBlock { block: 0, is_sprint_start: false, sprint_size: 64, is_span_start: false, span_size: 6400 },

        // Mid-sprint hardfork blocks (NOT sprint boundaries!)
        KnownBoundaryBlock { block: 50_523_000, is_sprint_start: false, sprint_size: 16, is_span_start: false, span_size: 6400 }, // Agra
        KnownBoundaryBlock { block: 83_756_500, is_sprint_start: false, sprint_size: 16, is_span_start: false, span_size: 1600 }, // Lisovo
    ]
}

/// Known mid-sprint hardfork details.
pub fn mid_sprint_hardforks() -> Vec<MidSprintHardfork> {
    vec![
        MidSprintHardfork {
            name: "Agra",
            block: 50_523_000,
            block_mod_16: 8,
            sprint_containing_start: 50_522_992,
            sprint_containing_end: 50_523_007,
            next_sprint_start: 50_523_008,
        },
        MidSprintHardfork {
            name: "Lisovo",
            block: 83_756_500,
            block_mod_16: 4,
            sprint_containing_start: 83_756_496,
            sprint_containing_end: 83_756_511,
            next_sprint_start: 83_756_512,
        },
    ]
}

// ============================================================================
// Types
// ============================================================================

/// A block with known parameter values (from protocol spec, not chain data).
#[derive(Debug, Clone)]
pub struct KnownParameterBlock {
    pub block: u64,
    pub era: &'static str,
    pub sprint_size: u64,
    pub span_size: u64,
    pub gas_limit_era: u64,
    pub base_fee_denom: u64,
    pub is_post_madhugiri: bool,
}

/// A block with known boundary conditions.
#[derive(Debug, Clone)]
pub struct KnownBoundaryBlock {
    pub block: u64,
    pub is_sprint_start: bool,
    pub sprint_size: u64,
    pub is_span_start: bool,
    pub span_size: u64,
}

/// A hardfork that activates mid-sprint.
#[derive(Debug, Clone)]
pub struct MidSprintHardfork {
    pub name: &'static str,
    pub block: u64,
    pub block_mod_16: u64,
    pub sprint_containing_start: u64,
    pub sprint_containing_end: u64,
    pub next_sprint_start: u64,
}
